#include <bits/stdc++.h>
using namespace std;

void solve() {
    int n;
    cin >> n;
    vector<int> arr(n);

    // Input array
    for(int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    // Add n to each occurrence of element
    // Using this, arr[i] % n gives original element
    // and arr[i] / n gives frequency
    for(int i = 0; i < n; i++) {
        arr[arr[i] % n] += n;
    }

    // Print frequencies and restore array
    for(int i = 0; i < n; i++) {
        cout << arr[i]/n << " ";
        arr[i] = arr[i] % n;  // restore array
    }
    cout << "\n";
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        solve();
    }
    return 0;
}
